on_write:
let res = #{ action: "Allow" };
if payload.contains("auto_tune") {
    res.auto_tune_requested = true;
}
res

on_read:
let res = #{ payload: payload };
res.match_found = true;
res

on_lifecycle:
let res = #{};
if payload.contains("auto_vacuum") && payload.auto_vacuum == true {
    res.clear_payload = true;
}
res
